"""sklearn.kernel_approximation — Kernel feature map approximations."""
import numpy as np
from sklearn.base import BaseEstimator, TransformerMixin


class RBFSampler(BaseEstimator, TransformerMixin):
    """Approximate an RBF kernel feature map using random Fourier features.

    Parameters
    ----------
    gamma : float, default=1.0
    n_components : int, default=100
    random_state : int or None, default=None
    """

    def __init__(self, gamma=1.0, n_components=100, random_state=None):
        self.gamma = gamma
        self.n_components = n_components
        self.random_state = random_state

    def fit(self, X, y=None):
        rng = np.random.RandomState(self.random_state)
        X = np.asarray(X, dtype=float)
        d = X.shape[1]
        self.random_weights_ = rng.normal(0, np.sqrt(2 * self.gamma), size=(d, self.n_components))
        self.random_offset_ = rng.uniform(0, 2 * np.pi, size=self.n_components)
        return self

    def transform(self, X):
        X = np.asarray(X, dtype=float)
        proj = X @ self.random_weights_ + self.random_offset_
        return np.sqrt(2.0 / self.n_components) * np.cos(proj)


class Nystroem(BaseEstimator, TransformerMixin):
    """Approximate kernel map using Nystroem method.

    Parameters
    ----------
    kernel : str, default='rbf'
    gamma : float, default=1.0
    n_components : int, default=100
    random_state : int or None, default=None
    """

    def __init__(self, kernel='rbf', gamma=1.0, n_components=100, random_state=None):
        self.kernel = kernel
        self.gamma = gamma
        self.n_components = n_components
        self.random_state = random_state

    def _kernel_func(self, X, Y):
        sq_dist = np.sum(X ** 2, axis=1, keepdims=True) + \
                  np.sum(Y ** 2, axis=1) - 2 * X @ Y.T
        return np.exp(-self.gamma * sq_dist)

    def fit(self, X, y=None):
        rng = np.random.RandomState(self.random_state)
        X = np.asarray(X, dtype=float)
        n = X.shape[0]
        n_comp = min(self.n_components, n)
        idx = rng.choice(n, size=n_comp, replace=False)
        self.components_ = X[idx]
        K_ss = self._kernel_func(self.components_, self.components_)
        U, S, Vt = np.linalg.svd(K_ss, full_matrices=False)
        S = np.maximum(S, 1e-12)
        self.normalization_ = U @ np.diag(1.0 / np.sqrt(S))
        return self

    def transform(self, X):
        X = np.asarray(X, dtype=float)
        K_xs = self._kernel_func(X, self.components_)
        return K_xs @ self.normalization_
